const d = JSON.parse((($input.first().json.stdout) || '{}').toString().trim());
const TH = 80; // threshold %
const checks = { disk: Number(d.disk_pct), ram: Number(d.ram_pct) };
const labels = { disk: 'Disk /', ram: 'RAM' };

const breached = Object.keys(checks).filter(k => checks[k] >= TH);

const store = $getWorkflowStaticData('global');
const prev = store.vg_dr || [];
const newly = breached.filter(k => !prev.includes(k));
const recovered = prev.filter(k => !breached.includes(k));
store.vg_dr = breached;

if (newly.length === 0 && recovered.length === 0) return [];

const lines = [];
if (newly.length) {
  lines.push('\uD83D\uDFE0 *VertiGuard \u2014 high resource usage*');
  newly.forEach(k => lines.push('\u2022 ' + labels[k] + ': ' + checks[k] + '% (\u2265' + TH + '%)'));
}
if (recovered.length) {
  if (lines.length) lines.push('');
  lines.push('\uD83D\uDFE2 *VertiGuard \u2014 resources back to normal*');
  recovered.forEach(k => lines.push('\u2022 ' + labels[k] + ': ' + checks[k] + '%'));
}
lines.push('');
lines.push('\uD83D\uDD52 ' + (d.ts || new Date().toISOString()));
return [{ json: { message: lines.join('\n') } }];
